import React from 'react';

const Sidebar = ({ activeMenu, setActiveMenu, appTheme, handleLogout }) => {
    const isDark = appTheme === 'dark';

    const menuItems = [
        { id: 'eksplorasi', label: 'Eksplorasi', icon: '🔍' },
        { id: 'favorit', label: 'Lowongan Favorit', icon: '⭐' },
        { id: 'status', label: 'Status Lamaran', icon: '📋' },
        { id: 'profil', label: 'Profil Saya', icon: '👤' },
        { id: 'password', label: 'Ganti Password', icon: '🔑' }
    ];

    return (
        <div className="sidebar">
            <div style={{ marginBottom: '32px', paddingLeft: '8px' }}>
                <h1 style={{ margin: 0, fontSize: '18px', fontWeight: '900', color: '#ea580c' }}>PasukanYerusSolo</h1>
                <span style={{ fontSize: '10px', fontWeight: '700', color: '#9e8476', textTransform: 'uppercase' }}>Job Portal Workspace</span>
            </div>

            <nav style={{ display: 'flex', flexDirection: 'column', gap: '8px', flex: 1 }}>
                {menuItems.map((item) => {
                    const isActive = activeMenu === item.id;
                    return (
                        <button
                            key={item.id}
                            onClick={() => setActiveMenu(item.id)}
                            style={{
                                display: 'flex', alignItems: 'center', gap: '12px', width: '100%',
                                padding: '12px 16px', borderRadius: '12px', border: 'none', cursor: 'pointer',
                                fontSize: '13px', fontWeight: '700', textAlign: 'left',
                                background: isActive ? 'linear-gradient(135deg, #ea580c 0%, #f59e0b 100%)' : 'transparent',
                                color: isActive ? '#ffffff' : '#9e8476',
                                transition: 'all 0.2s'
                            }}
                        >
                            <span style={{ fontSize: '16px' }}>{item.icon}</span>
                            {item.label}
                        </button>
                    );
                })}
            </nav>

            <div style={{ borderTop: '1px solid #22140a', paddingTop: '16px' }}>
                <div style={{ marginBottom: '16px', padding: '10px', borderRadius: '8px', fontSize: '11px', color: '#9e8476' }}>
                    Otoritas: <span style={{ color: '#ea580c', fontWeight: '800' }}>Pelamar</span>
                </div>
                <button onClick={handleLogout} style={{ width: '100%', padding: '10px', background: 'transparent', border: '1px solid #ef4444', color: '#ef4444', borderRadius: '8px', cursor: 'pointer', fontWeight: '700' }}>
                    Keluar Akun
                </button>
            </div>
        </div>
    );
};

export default Sidebar;
